from typing import List

def solve(nums: List[int]) -> int:
    if not nums or len(nums) < 2:
        return 0
    left, right = 0, len(nums) - 1
    max_area = 0
    while left < right:
        width = right - left
        height = min(nums[left], nums[right])
        max_area = max(max_area, width * height)
        if nums[left] < nums[right]:
            left += 1
        else:
            right -= 1
    return max_area
